// Emits one 140-byte buffer per device per tick.
// State per IMEI is kept in flow context.

const env_data = env.get('Devices');
if (!env_data || !env_data.data) {
    node.error('Devices env var not set');
    return null;
}
const devices = env_data.data;

const MODEL_CODES = {
    'TEK 766': 0x00, 'TEK 586': 0x02, 'TEK 790': 0x03, 'TEK 733': 0x05,
    'TEK 643': 0x06, 'TEK 811': 0x07, 'TEK 822': 0x08, 'TEK 733A': 0x09
};

// Per-scenario cm target (cm = distance from top, so HIGH = empty tank).
//   normal   -> ~75% full (cm at 25% of max)
//   warning  -> ~32% full (cm at 68% of max)
//   critical -> ~8% full  (cm at 92% of max, triggers low_level alarm)
//   inactive -> any (emitted with stale timestamp)
const SCENARIO_CM_FRAC = {
    normal:   { target: 0.25, jitter: 0.06 },
    warning:  { target: 0.68, jitter: 0.04 },
    critical: { target: 0.92, jitter: 0.03 },
    inactive: { target: 0.40, jitter: 0.05 }
};

function initState(device) {
    const maxCm = device.max_cm || 200;
    const sc = SCENARIO_CM_FRAC[device.scenario || 'normal'];
    return {
        cm: Math.round(maxCm * (sc.target + (Math.random() - 0.5) * sc.jitter)),
        temp: 25 + Math.random() * 10,
        battery_volt: 5.5 + (Math.random() - 0.5) * 0.5,
        gsm: 60 + Math.floor(Math.random() * 100),
        msg_count: 0,
        tick: 0,
        last_refill: false,
        last_drop: false,
        history: []
    };
}

function evolveState(state, device) {
    state.tick++;
    state.msg_count++;
    const maxCm = device.max_cm || 200;
    const sc = SCENARIO_CM_FRAC[device.scenario || 'normal'];
    const targetCm = maxCm * sc.target;

    // Quick mean-revert to scenario target so the tank never accidentally
    // flips between states.
    state.cm += (targetCm - state.cm) * 0.18;
    state.cm += (Math.random() - 0.5) * maxCm * sc.jitter * 0.4;
    state.cm = Math.max(0, Math.min(maxCm, Math.round(state.cm)));

    state.last_refill = false;
    state.last_drop = false;

    // Temperature drift
    state.temp += (Math.random() - 0.5) * 0.5;
    state.temp = Math.max(15, Math.min(45, state.temp));

    // Battery decay (recharge if very low)
    if (state.battery_volt < 3.5) state.battery_volt = 5.5;
    else state.battery_volt -= 0.001 + Math.random() * 0.002;

    // GSM drift
    state.gsm += Math.floor((Math.random() - 0.5) * 20);
    state.gsm = Math.max(0, Math.min(255, state.gsm));

    // History (most recent first, max 28)
    state.history.unshift({
        cm: Math.round(state.cm),
        temp: Math.round(state.temp * 2) / 2,
        ultrasonic_rssi: Math.floor(150 + Math.random() * 80),
        src: Math.floor(Math.random() * 16)
    });
    if (state.history.length > 28) state.history.pop();

    return state;
}

function encodePayload(state, device) {
    const buf = Buffer.alloc(140);

    // [0] Model code
    buf[0] = MODEL_CODES[device.model] !== undefined ? MODEL_CODES[device.model] : 0x05;

    // [1] HW Revision (0 = UC20, non-zero top-5-bits = UC15)
    buf[1] = device.hw_uc15 ? 0x08 : 0x00;

    // [2] SW Version: top 3 bits = major, bottom 5 bits = minor (decoder formats as "minor.major")
    const swMajor = device.sw_major !== undefined ? device.sw_major : 0;
    const swMinor = device.sw_minor !== undefined ? device.sw_minor : 5;
    buf[2] = ((swMajor & 0x07) << 5) | (swMinor & 0x1F);

    // [3] Reason flags (MSB first)
    let reason = 0;
    if (state.last_refill) reason |= 0x80;
    if (state.last_drop) reason |= 0x40;
    reason |= 0x01; // scheduled
    if (state.cm > (device.max_cm || 200) - 20) reason |= 0x02; // tank low alarm
    buf[3] = reason;

    // [4] Alarm flags
    let alarm = 0;
    if (state.cm > (device.max_cm || 200) - 20) alarm |= 0x80; // active (tank low)
    buf[4] = alarm;

    // [5] GSM RSSI
    buf[5] = state.gsm & 0xFF;

    // [6] Battery: bit1=act_3g, bit2=RTC_set, bottom 5 bits = (volt*10)-30
    const voltVal = Math.max(0, Math.min(31, Math.round(state.battery_volt * 10 - 30)));
    buf[6] = 0x40 | 0x20 | voltVal;

    // [7-14] IMEI as BCD (each byte's hex value = 2 decimal digits)
    const imeiStr = String(device.IMEI).padStart(16, '0');
    for (let i = 0; i < 8; i++) {
        const pair = imeiStr.substring(i * 2, i * 2 + 2);
        buf[7 + i] = parseInt(pair, 16);
    }

    // [15] Message type
    buf[15] = 0x3B;

    // [16] msg_length low byte
    buf[16] = 0x10;

    // [17-18] msg_count (uint16 BE)
    buf[17] = (state.msg_count >> 8) & 0xFF;
    buf[18] = state.msg_count & 0xFF;

    // [19] tickets (top 3 bits, 0) + RTC hours (bottom 5 bits)
    const now = new Date();
    buf[19] = now.getHours() & 0x1F;

    // [20-21] error code
    buf[20] = 0;
    buf[21] = 0;

    // [22] reserved
    buf[22] = 0;

    // [23] logger interval: 0x80 = 15 min
    buf[23] = 0x80;

    // [24] count_to_log
    buf[24] = state.tick % 256;

    // [25] RTC minutes
    buf[25] = now.getMinutes();

    // [26-137] history: 28 records x 4 bytes
    for (let r = 0; r < Math.min(state.history.length, 28); r++) {
        const rec = state.history[r];
        const off = 26 + r * 4;
        buf[off + 0] = rec.ultrasonic_rssi & 0xFF;
        buf[off + 1] = Math.max(0, Math.min(255, Math.round((rec.temp + 30) * 2)));
        // byte[2]: top 2 bits free, bits 2-5 = SRC (4 bits), bottom 2 bits = cm high 2 bits
        buf[off + 2] = ((rec.src & 0x0F) << 2) | ((rec.cm >> 8) & 0x03);
        buf[off + 3] = rec.cm & 0xFF;
    }
    // [138-139] unused

    return buf;
}

// Main: one message per device
for (let i = 0; i < devices.length; i++) {
    const device = devices[i];
    const stateKey = 'tank_state_' + device.IMEI;
    let state = flow.get(stateKey) || initState(device);
    state = evolveState(state, device);
    flow.set(stateKey, state);

    node.send({ payload: encodePayload(state, device), _imei: device.IMEI, _scenario: device.scenario || 'normal' });
}

return null;

// Rebuild of original Canar decoder. Returns ONE combined message
// containing header info + latest reading + history, ready for the formatter.

const env_data = env.get('Devices');
const devices = env_data.data;

const payload_size = msg.payload.length;
const decimal_data = msg.payload;
const hex_array = [];
for (let i = 0; i < decimal_data.length; i++) {
    let h = decimal_data[i].toString(16);
    if (h.length === 1) h = '0' + h;
    hex_array.push(h);
}

const info = {};
info.raw_payload = hex_array.join('');

// Model
const MODEL_MAP = {
    '00': 'TEK 766', '02': 'TEK 586', '03': 'TEK 790', '05': 'TEK 733',
    '06': 'TEK 643', '07': 'TEK 811', '08': 'TEK 822', '09': 'TEK 733A'
};
info.model = MODEL_MAP[hex_array[0]] || 'UNKNOWN';

// HW Revision
const byte1 = parseInt(hex_array[1], 16).toString(2).padStart(8, '0');
info.HW_Revision = (parseInt(byte1.slice(0, 5), 2) === 0) ? 'UC20' : 'UC15';

// SW Version (decoder convention: "minor.major")
const byte2 = parseInt(hex_array[2], 16).toString(2).padStart(8, '0');
info.SW_version = parseInt(byte2.slice(-5), 2) + '.' + parseInt(byte2.slice(0, 3), 2);

// Reason flags
const byte3 = parseInt(hex_array[3], 16).toString(2).padStart(8, '0');
info.Reason = {
    dynamic_Limit2: byte3[0] === '1',
    dynamic_Limit: byte3[1] === '1',
    tsp_request: byte3[2] === '1',
    reboot: byte3[3] === '1',
    manual: byte3[4] === '1',
    server_request: byte3[5] === '1',
    alarm: byte3[6] === '1',
    scheduled: byte3[7] === '1'
};

// Alarm flags
const byte4 = parseInt(hex_array[4], 16).toString(2).padStart(8, '0');
info.Alarm = {
    active: byte4[0] === '1',
    bund_status: byte4[4] === '1',
    limit3: byte4[5] === '1',
    limit2: byte4[6] === '1',
    limit1: byte4[7] === '1'
};

// GSM
info.GSM = parseInt(hex_array[5], 16);

// Battery
const byte6 = parseInt(hex_array[6], 16).toString(2).padStart(8, '0');
const volt = (parseInt(byte6.slice(-5), 2) + 30) / 10;
info.Battery = {
    act_3g: byte6[1] === '1',
    RTC_set: byte6[2] === '1',
    volt: volt
};
info.Battery_level = Math.max(0, Math.min(100, Math.round(((volt - 3.4) * 100) / 2.6)));

// IMEI (BCD across bytes 7-14)
let IMEI = '';
for (let i = 7; i <= 14; i++) IMEI += hex_array[i];
info.IMEI = parseInt(IMEI);
const matched = devices.find(d => parseInt(d.IMEI) === info.IMEI);
info.device_name = matched ? matched.name : 'UNKNOWN';

// Misc header
const byte15 = parseInt(hex_array[15], 16).toString(2).padStart(8, '0');
info.msg_type = parseInt(byte15.slice(-6), 2);
info.msg_count = (parseInt(hex_array[17], 16) * 256) + parseInt(hex_array[18], 16);

// Logger interval
const byte23hex = hex_array[23];
let logger;
if (byte23hex === '00') logger = 1;
else if (byte23hex === '80') logger = 15;
else logger = parseInt(parseInt(byte23hex, 16).toString(2).padStart(8, '0').slice(-7), 2) * 15;
info.logger = logger;

// RTC
const byte19 = parseInt(hex_array[19], 16).toString(2).padStart(8, '0');
const RTC_hours = parseInt(byte19.slice(-5), 2);
const RTC_minutes = parseInt(hex_array[25], 16);
info.RTC = String(RTC_hours).padStart(2, '0') + ':' + String(RTC_minutes).padStart(2, '0');

// Historical data
const hex_data_length = (hex_array.length - 28) / 4;
const hex_data = [];
let index = 26;
for (let i = 0; i < hex_data_length; i++) {
    hex_data.push(hex_array.slice(index, index + 4).join(''));
    index += 4;
}

const data = [];
let current_RTC = (RTC_hours * 60) + RTC_minutes;
for (let i = 0; i < hex_data.length; i++) {
    if (hex_data[i] === '00000000') continue;
    const bit_2_3 = parseInt(hex_data[i].slice(4, 6), 16).toString(2).padStart(8, '0');
    const bit_0_1 = parseInt(hex_data[i].slice(-2), 16).toString(2).padStart(8, '0');
    const cm = parseInt((bit_2_3 + bit_0_1).slice(-10), 2);
    const SRC = parseInt(bit_2_3.slice(2, 6), 2);
    const Ultrasonic_RSSI = parseInt(hex_data[i].slice(0, 2), 16);
    const temp = (parseInt(hex_data[i].slice(2, 4), 16) / 2) - 30;
    const rtc_h = Math.floor(Math.abs(current_RTC) / 60);
    const rtc_m = Math.abs(current_RTC) % 60;
    data.push({
        payload: hex_data[i],
        RTC: String(rtc_h).padStart(2, '0') + ':' + String(rtc_m).padStart(2, '0'),
        cm: cm,
        SRC: SRC,
        Ultrasonic_RSSI: Ultrasonic_RSSI,
        temp: temp,
        IMEI: info.IMEI,
        refill: info.Reason.dynamic_Limit2,
        drop: info.Reason.dynamic_Limit
    });
    current_RTC -= logger;
}

const latest = data[0] || { cm: 0, SRC: 0, Ultrasonic_RSSI: 0, temp: 0, RTC: '00:00' };
info.latest = {
    cm: latest.cm,
    temp: latest.temp,
    ultrasonic_rssi: latest.Ultrasonic_RSSI,
    src: latest.SRC,
    rtc: latest.RTC
};
info.alarm_low_level = (info.latest.cm < 20);
info.history = data;

// Validation
const VALID_IMEIS = [860147043918943, 860147043918944, 860147043923083, 860147043923084, 860147043923085, 860147043923086];
if (!VALID_IMEIS.includes(info.IMEI) || payload_size !== 140) {
    node.warn('Invalid payload: IMEI=' + info.IMEI + ', size=' + payload_size);
    return null;
}

msg.payload = info;
return msg;

// Enrich decoded payload with site info and shape it for the React frontend.

const info = msg.payload;
const env_data = env.get('Devices');
const device = env_data.data.find(d => parseInt(d.IMEI) === info.IMEI);
if (!device) return null;

const latest = info.latest || {};
const tankMaxCm = device.max_cm || 200;
const tankCapacity = device.capacity_liters || 1000;
// Sensor measures distance from top to fuel surface (ullage). Convert to fuel depth.
const fuelDepthCm = Math.max(0, tankMaxCm - (latest.cm || 0));
const levelPercent = Math.max(0, Math.min(100, (fuelDepthCm / tankMaxCm) * 100));
const volume = Math.round((fuelDepthCm / tankMaxCm) * tankCapacity);
const alarmLowLevel = fuelDepthCm < 20;

// Inactive devices report a stale timestamp (2 minutes old) so the
// dashboard treats them as offline.
const nowTs = Date.now();
const tsMs = msg._scenario === 'inactive' ? nowTs - 120000 : nowTs;
const tsIso = new Date(tsMs).toISOString();

msg.payload = {
    type: 'tank_update',
    timestamp: tsIso,
    imei: info.IMEI,
    device: info.device_name,
    site: {
        name: device.site_name || device.name,
        city: device.city,
        address: device.address,
        lat: device.lat,
        long: device.long
    },
    tank: {
        capacity_liters: tankCapacity,
        max_cm: tankMaxCm
    },
    reading: {
        cm: latest.cm,
        fuel_depth_cm: fuelDepthCm,
        level_percent: Math.round(levelPercent * 10) / 10,
        volume_liters: volume,
        temperature_c: latest.temp,
        ultrasonic_rssi: latest.ultrasonic_rssi,
        src: latest.src,
        rtc: latest.rtc
    },
    device_status: {
        model: info.model,
        hw_revision: info.HW_Revision,
        sw_version: info.SW_version,
        battery_volt: Math.round(info.Battery.volt * 10) / 10,
        battery_percent: info.Battery_level,
        gsm_signal: info.GSM,
        logger_interval_min: info.logger
    },
    alarms: {
        low_level: alarmLowLevel,
        active: info.Alarm.active,
        bund_status: info.Alarm.bund_status,
        limit1: info.Alarm.limit1,
        limit2: info.Alarm.limit2,
        limit3: info.Alarm.limit3
    },
    events: {
        refill: info.Reason.dynamic_Limit2,
        drop: info.Reason.dynamic_Limit,
        scheduled: info.Reason.scheduled
    },
    raw_payload_hex: info.raw_payload
};

return msg;
